1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  cursed?: boolean;
8	  enchantment?: number;
9	};
10	
11	export type QuoteStep = {
12	  op: "quote";
13	  items: Item[];
14	};
15	
16	export type Step = QuoteStep;
17	
18	export type Scenario = {
19	  customer: Customer;
20	  steps: Step[];
21	};
22	
23	export type QuoteResult = {
24	  premium: number;
25	};
26	
27	export type Result = QuoteResult;
28	
29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	const CURSE_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_MINIMUM = 5;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const LOYALTY_MINIMUM_YEARS = 2;
36	
37	const BASE_PREMIUMS: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const COMPONENT_BLOCK_SIZE = 3;
47	const COMPONENT_BLOCK_PREMIUM = 60;
48	
49	const countByType = (items: Item[]): Map<string, number> => {
50	  const counts = new Map<string, number>();
51	  for (const item of items) {
52	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
53	  }
54	  return counts;
55	};
56	
57	const groupBasePremium = (type: string, count: number): number =>
58	  count === COMPONENT_BLOCK_SIZE
59	    ? COMPONENT_BLOCK_PREMIUM
60	    : count * BASE_PREMIUMS[type];
61	
62	const computeBasePremium = (items: Item[]): number =>
63	  [...countByType(items)].reduce(
64	    (total, [type, count]) => total + groupBasePremium(type, count),
65	    0,
66	  );
67	
68	const itemCurseSurcharge = (item: Item): number =>
69	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
70	
71	const computeCurseSurcharge = (items: Item[]): number =>
72	  items.reduce((total, item) => total + itemCurseSurcharge(item), 0);
73	
74	const itemEnchantmentSurcharge = (item: Item): number =>
75	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MINIMUM
76	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
77	    : 0;
78	
79	const computeEnchantmentSurcharge = (items: Item[]): number =>
80	  items.reduce((total, item) => total + itemEnchantmentSurcharge(item), 0);
81	
82	const computeLoyaltyDiscount = (
83	  customer: Customer,
84	  basePremium: number,
85	): number =>
86	  customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
87	    ? basePremium * LOYALTY_DISCOUNT_RATE
88	    : 0;
89	
90	const quotePremium = (customer: Customer, items: Item[]): number => {
91	  const basePremium = computeBasePremium(items);
92	  const curseSurcharge = computeCurseSurcharge(items);
93	  const enchantmentSurcharge = computeEnchantmentSurcharge(items);
94	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
95	  const loyaltyDiscount = computeLoyaltyDiscount(customer, basePremium);
96	  const exactPremium =
97	    basePremium +
98	    curseSurcharge +
99	    enchantmentSurcharge +
100	    firstInsuranceSurcharge -
101	    loyaltyDiscount +
102	    PROCESSING_FEE;
103	  return Math.ceil(exactPremium);
104	};
105	
106	export const processScenario = (scenario: Scenario): { results: Result[] } => {
107	  return {
108	    results: [
109	      { premium: quotePremium(scenario.customer, scenario.steps[0].items) },
110	    ],
111	  };
112	};
